// logger.info('Server started', { port: 3000 });
// logger.warn('High memory');
// logger.error('Crash', { code: 1 });

exercises.solution:
function createLogger(minLevel = 2) {
  const levels = { error: 0, warn: 1, info: 2 };

  function log(level, message, meta = {}) {
    if (levels[level] > minLevel) return;
    const timestamp = new Date().toISOString();
    const metaStr = Object.keys(meta).length ? ' ' + JSON.stringify(meta) : '';
    console.log(`[${level.toUpperCase()}] [${timestamp}] ${message}${metaStr}`);
  }

  return {
    info: (msg, meta) => log('info', msg, meta),
    warn: (msg, meta) => log('warn', msg, meta),
    error: (msg, meta) => log('error', msg, meta)
  };
}

const logger = createLogger(2);
logger.info('Server started', { port: 3000 });
logger.warn('High memory usage');
logger.error('Database crash', { code: 'ECONNREFUSED' });

console.log('---');
const errorOnly = createLogger(0);
errorOnly.info('This will not appear');
errorOnly.error('Only errors appear');

