// Create calculator object with add, subtract, multiply, divide
// divide(a, 0) should throw Error('Cannot divide by zero')
// Then simulate tests by checking results

// Your code here

// Simulate tests:
// console.log('add(2,3) = 5:', calculator.add(2,3) === 5);
// console.log('subtract(10,4) = 6:', calculator.subtract(10,4) === 6);
// etc.

exercises.solution:
const calculator = {
  add: (a, b) => a + b,
  subtract: (a, b) => a - b,
  multiply: (a, b) => a * b,
  divide: (a, b) => {
    if (b === 0) throw new Error('Cannot divide by zero');
    return a / b;
  }
};

// Simulate test suite
console.log('Calculator Tests:');
console.log('  add(2,3) = 5:', calculator.add(2, 3) === 5);
console.log('  subtract(10,4) = 6:', calculator.subtract(10, 4) === 6);
console.log('  multiply(3,4) = 12:', calculator.multiply(3, 4) === 12);
console.log('  divide(10,2) = 5:', calculator.divide(10, 2) === 5);

try {
  calculator.divide(5, 0);
  console.log('  divide(5,0) throws: false');
} catch (e) {
  console.log('  divide(5,0) throws:', e.message === 'Cannot divide by zero');
}

