exercises.solution:
class OrderService {
  constructor(db) {
    this.db = db;
  }

  async getOrder(id) {
    const order = await this.db.findOrder(id);
    if (!order) throw new Error('Order not found');
    return order;
  }
}

// Mock database
const mockDb = {
  findOrder: async (id) => {
    const orders = { 1: { id: 1, item: 'Laptop', total: 999 } };
    return orders[id] || null;
  }
};

const service = new OrderService(mockDb);

async function runTests() {
  // Test: order found
  const order = await service.getOrder(1);
  console.log('Found order:', order.item === 'Laptop');

  // Test: order not found
  try {
    await service.getOrder(99);
    console.log('Should have thrown: false');
  } catch (e) {
    console.log('Not found throws:', e.message === 'Order not found');
  }
}

runTests();
